UPDATE produits_complementaires SET phrase_conseil = sub.phrase
FROM (VALUES ('b8f55183-9bc8-4e57-8e17-2cf13d7e3d7c'::uuid, 'Un déficit en magnésium peut favoriser les crises de migraine, le bisglycinate aide à réguler l''excitabilité neuronale et à réduire leur fréquence.'),('b7f51ddc-36ad-4e54-abf6-04269742977e'::uuid, 'Le baume du Tigre aide à stimuler la circulation sanguine et à décontracter les muscles, soulageant ainsi les tensions à l''origine des migraines.'),('49a47404-3b3f-4e28-88dd-02c2f3517c0e'::uuid, 'L''application de menthe poivrée sur les tempes crée un effet froid, aidant à soulager la douleur en réduisant l''inflammation locale et la tension musculaire.'),('5c252385-c8e8-4ade-bec7-3e23f8c6e851'::uuid, 'La mycose cutanée est causée par des champignons, cette crème antifongique agit localement pour éliminer l''infection et restaurer l''intégrité de la peau.'),('92aefcac-0059-4079-b365-2e4b8bdc2d3f'::uuid, 'Les champignons prolifèrent sur la peau, ce spray agit comme antifongique pour éliminer l''infection cutanée et prévenir sa propagation.'),('07789876-4245-4c3a-aff7-f257eb90c449'::uuid, 'L''humidité favorise la croissance des champignons, cette poudre antifongique aide à maintenir la sécheresse et à empêcher leur prolifération.'),('7ea9931b-c127-4786-bf4c-9eb881d76878'::uuid, 'Les mycoses superficielles sont des infections fongiques locales, cette crème antifongique cible le champignon pour éliminer la lésion cutanée.'),('4dd915b6-1706-4727-ba30-085a7775d9e9'::uuid, 'L''humidité persistante favorise les mycoses, cette poudre aide à assécher la zone affectée pour inhiber la croissance des champignons et prévenir les récidives.'),('2e7f3bc6-e048-4261-95f7-01a8cd389f4c'::uuid, 'Les spores de champignons peuvent rester dans les chaussures et provoquer une recontamination, ce spray désinfecte pour rompre le cycle infectieux.'),('e8f07cc7-7a0e-4cbf-a9b6-5dca35eaa903'::uuid, 'Les nausées résultent d''une stimulation du centre du vomissement, la métopimazine agit sur les récepteurs dopaminergiques pour bloquer cette sensation.'),('f93627c3-9220-4f15-bf85-9e4dc2a94d35'::uuid, 'Le gingembre agit sur les récepteurs sérotoninergiques, réduisant ainsi la sensation de nausée et les vomissements.'),('763b4ac1-830a-4c3e-949d-bd82da891bc4'::uuid, 'Le gingembre module les signaux nerveux vers le centre du vomissement, ces gélules réduisent la sensation de nausée de manière naturelle.'),('d3b2a5a0-5f5f-48de-a3c7-fd12b47d002e'::uuid, 'Les nausées simples sont dues à une irritation gastro-intestinale ou des signaux nerveux, cet antiémétique OTC agit rapidement pour soulager la sensation.'),('57a0763d-0477-49d8-a5a9-8acdbf8b017b'::uuid, 'Les nausées peuvent être apaisées par des saveurs acides, l''eau gazeuse citronnée aide à calmer l''estomac par un simple effet physiologique.'),('faa2199e-a9fe-4c03-9c69-a97ff9c80f07'::uuid, 'Le baume du Tigre, par son action chauffante, aide à stimuler la circulation locale et à réduire l''inflammation nerveuse associée à la névralgie.'),('f627b5c4-d27a-4b02-8fe5-46fca9f0f8c5'::uuid, 'La thermothérapie modifie le flux sanguin et la conduction nerveuse, une poche chaude ou froide aide à moduler la douleur névralgique.'),('2a5ead35-7b59-4f48-a878-e361c99b0d8b'::uuid, 'L''inflammation articulaire due à la polyarthrite cause des douleurs, ce gel anti-inflammatoire réduit localement l''inflammation.'),('53cfb87f-4da2-4e69-83b6-f966b21818b3'::uuid, 'Les poussées dentaires provoquent une inflammation gingivale, l''anneau réfrigéré engourdit la zone pour calmer l''irritation thermique.'),('ddfe50cf-7bee-4020-8ad9-58b5776d8985'::uuid, 'L''éruption dentaire irrite la gencive, le gel gingival crée un film protecteur pour la soulager.'),('53b0e745-bba9-450f-8158-bbb48baebfa1'::uuid, 'Les poussées dentaires peuvent perturber les jeunes enfants, les granules homéopathiques agissent pour moduler les déséquilibres.'),('19181645-234d-44d8-8b58-077667f37ef8'::uuid, 'Les poux s''accrochent aux cheveux pour se nourrir, ce shampoing à la diméticone étouffe les poux en obstruant leurs orifices respiratoires.'),('0fb6d8d9-3dd5-4d1d-98e7-dbf1edecfcc5'::uuid, 'Les poux adhèrent fermement aux cheveux, ce traitement à la diméticone forme une pellicule qui immobilise mécaniquement les parasites et les lentes.'),('90d0c9e5-a1bc-422e-96d0-d7718be4bd6d'::uuid, 'Les lentes sont résistantes aux traitements chimiques, le peigne métallique permet de les décrocher physiquement des cheveux.'),('2c19521f-edad-4d7b-9889-dbbb33549745'::uuid, 'La pré-ménopause s''accompagne de modifications physiologiques, les multivitamines compensent les carences nutritionnelles potentielles.'),('9cf19617-f2b5-4036-9c19-ec7bfcc8d1cc'::uuid, 'La baisse des hormones féminines cause des symptômes de pré-ménopause, les isoflavones de soja miment l''action des œstrogènes pour les atténuer.'),('a6e0a7a3-3b03-446b-8e7d-c6ea353fc6c9'::uuid, 'Les fluctuations hormonales de la pré-ménopause peuvent altérer le système nerveux, le magnésium et la B6 favorisent l''équilibre neuronal.'),('36fafdc5-90f7-4d95-b648-7aa8408dc528'::uuid, 'En hiver, le système immunitaire est plus sollicité, la Vitamine D3 et le Zinc soutiennent les défenses naturelles de l''organisme.'),('30b3b481-8e5b-4b60-a00f-4e588675e415'::uuid, 'Le froid saisonnier peut affaiblir les défenses immunitaires, la Vitamine C et le Zinc renforcent la fonction immunitaire.'),('b0751e76-da4a-4e89-a593-7978001f49b1'::uuid, 'Le manque d''ensoleillement hivernal réduit la synthèse de vitamine D, la supplémentation optimise le fonctionnement immunitaire.'),('5eca8568-5e1d-468e-bb8c-6e619b9c4ac5'::uuid, 'La peau irritée sécrète des médiateurs de démangeaisons, cette crème anti-démangeaisons bloque l''action de ces médiateurs pour apaiser.')) AS sub(id, phrase)
WHERE produits_complementaires.id = sub.id;